func main() {
    // Initialize a channel to handle incoming requests
    reqChan := make(chan struct{}, 10) // buffer size for 10 requests

    // Initialize a mutex to synchronize access to the image file
    mu := &sync.Mutex{}

    // Initialize a wait group to wait for all goroutines to finish
    var wg sync.WaitGroup

    // Start a goroutine to handle incoming requests
    go func() {
        for {
            select {
            case <-reqChan:
                // Handle the incoming request
                handleRequest()
            }
        }
    }()

    // Start a goroutine to handle incoming requests
    for i := 0; i < 10; i++ {
        wg.Add(1)
        go func() {
            defer wg.Done()
            reqChan <- struct{}{}
        }()
    }

    // Wait for all goroutines to finish
    wg.Wait()

    // Close the channel to signal the end of requests
    close(reqChan)
}

func handleRequest() {
    // Get the filename and dimensions from the request
    filename := "image.jpg"
    width, height := 800, 600

    // Open the image file
    file, err := os.Open(filename)
    if err != nil {
        log.Println(err)
        return
    }
    defer file.Close()

    // Decode the image
    img, err := jpeg.Decode(file)
    if err != nil {
        log.Println(err)
        return
    }

    // Resize the image
    resizedImg := resizeImage(img, width, height)

    // Send the resized image to the requester
    sendResizedImage(resizedImg)
}

func resizeImage(img image.Image, width, height int) image.Image {
    // Calculate the aspect ratio
    aspectRatio := float64(img.Bounds().Dx()) / float64(img.Bounds().Dy())

    // Calculate the new dimensions
    if float64(width)/float64(height) > aspectRatio {
        newWidth := height * aspectRatio
        newHeight := height
    } else {
        newWidth := width
        newHeight := width / aspectRatio
    }

    // Resize the image
    resizedImg := image.NewImage(image.Rect(0, 0, int(newWidth), int(newHeight)))
    resizedImg = resize(resizedImg, img, width, height)

    return resizedImg
}

func resize(img image.Image, width, height int) image.Image {
    // Create a new image with the specified dimensions
    newImg := image.NewImage(image.Rect(0, 0, width, height))

    // Copy the pixels from the original image to the new image
    for y := 0; y < height; y++ {
        for x := 0; x < width; x++ {
            pixel := img.At(x, y)
            newImg.Set(x, y, pixel)
        }
    }

    return newImg
}

func sendResizedImage(img image.Image) {
    // Open a file to save the resized image
    file, err := os.Create("resized_image.jpg")
    if err != nil {
        log.Println(err)
        return
    }
    defer file.Close()

    // Encode the image as a JPEG
    err = jpeg.Encode(file, img, nil)
    if err != nil {
        log.Println(err)
        return
    }

    // Print a success message
    fmt.Println("Resized image sent successfully")
}
