func main() {
    // Set directory path
    directory := "./files"

    // Check if directory exists
    if _, err := os.Stat(directory); os.IsNotExist(err) {
        log.Fatal("Directory does not exist")
    }

    // Get all files in the directory
    files, err := os.ReadDir(directory)
    if err != nil {
        log.Fatal(err)
    }

    // Create a channel for file encryption status
    statusChan := make(chan FileEncryptionStatus)

    // Create a mutex for logging
    logMutex := &sync.Mutex{}

    // Create a goroutine pool
    pool := make(chan struct{}, 10)

    // Encrypt files in parallel
    for _, file := range files {
        if file.IsDir() {
            continue
        }
        go func(filename string) {
            defer pool <- struct{}{}
            defer func() {
                pool <- struct{}{}
            }()

            // Check if file can be read
            file, err := os.Open(filename)
            if err != nil {
                logMutex.Lock()
                log.Printf("Error opening file %s: %v", filename, err)
                logMutex.Unlock()
                statusChan <- FileEncryptionStatus{FileName: filename, Success: false, Message: err.Error()}
                return
            }
            defer file.Close()

            // Read file content
            content, err := file.ReadAll()
            if err != nil {
                logMutex.Lock()
                log.Printf("Error reading file %s: %v", filename, err)
                logMutex.Unlock()
                statusChan <- FileEncryptionStatus{FileName: filename, Success: false, Message: err.Error()}
                return
            }
            defer func() {
                if err := file.Close(); err != nil {
                    logMutex.Lock()
                    log.Printf("Error closing file %s: %v", filename, err)
                    logMutex.Unlock()
                }
            }()

            // Create a new AES cipher
            block, err := aes.NewCipher([]byte{0x01, 0x02, 0x03, 0x04, 0x05, 0x06, 0x07, 0x08, 0x09, 0x10, 0x11, 0x12, 0x13, 0x14, 0x15, 0x16})
            if err != nil {
                logMutex.Lock()
                log.Printf("Error creating AES cipher: %v", err)
                logMutex.Unlock()
                statusChan <- FileEncryptionStatus{FileName: filename, Success: false, Message: err.Error()}
                return
            }
            defer func() {
                if err := block.Close(); err != nil {
                    logMutex.Lock()
                    log.Printf("Error closing AES cipher: %v", err)
                    logMutex.Unlock()
                }
            }()

            // Encrypt file content
            encryptedContent := make([]byte, len(content))
            stream := cipher.NewCFBEncrypter(block)
            _, err = io.ReadFull(rand.Reader, encryptedContent)
            if err != nil {
                logMutex.Lock()
                log.Printf("Error encrypting file %s: %v", filename, err)
                logMutex.Unlock()
                statusChan <- FileEncryptionStatus{FileName: filename, Success: false, Message: err.Error()}
                return
            }
            for i := range encryptedContent {
                encryptedContent[i] = stream.XOR(content[i])
            }
            defer func() {
                if err := stream.Close(); err != nil {
                    logMutex.Lock()
                    log.Printf("Error closing AES cipher: %v", err)
                    logMutex.Unlock()
                }
            }()

            // Save encrypted content to a new file
            err = os.WriteFile(filename+".enc", encryptedContent, 0644)
            if err != nil {
                logMutex.Lock()
                log.Printf("Error writing encrypted file %s: %v", filename, err)
                logMutex.Unlock()
                statusChan <- FileEncryptionStatus{FileName: filename, Success: false, Message: err.Error()}
                return
            }
            defer func() {
                if err := os.Remove(filename); err != nil {
                    logMutex.Lock()
                    log.Printf("Error removing original file %s: %v", filename, err)
                    logMutex.Unlock()
                }
            }()

            // Log encryption status
            logMutex.Lock()
            log.Printf("File %s encrypted successfully", filename)
            logMutex.Unlock()
            statusChan <- FileEncryptionStatus{FileName: filename, Success: true}
        }(file.Name())
    }

    // Close the goroutine pool
    close(pool)

    // Read and log file encryption status
    for status := range statusChan {
        logMutex.Lock()
        log.Printf("File %s %s\n", status.FileName, status.Success? " successfully" : " failed")
        logMutex.Unlock()
    }
}
