class Task(val name: String, val priority: Int, val lambdaExpression: () -> Unit)

// Define a PriorityQueue to store tasks based on priority
class PriorityQueueTaskScheduler {
    private val priorityQueue = PriorityQueue<Task> { t1, t2 ->
        if (t1.priority == t2.priority) {
            t1.name.compareTo(t2.name)
        } else {
            t2.priority - t1.priority
        }
    }

    // Method to add a task to the priority queue
    fun addTask(task: Task) {
        priorityQueue.add(task)
    }

    // Method to execute tasks in the priority queue
    fun executeTasks() {
        while (!priorityQueue.isEmpty()) {
            val task = priorityQueue.poll()
            task.lambdaExpression()
            println("Task $task.name executed")
        }
    }
}

// Example usage
