    val scheduler = PriorityQueueTaskScheduler()

    // Define tasks using lambda expressions
    val task1 = Task("Task 1", 1, { println("Task 1 executed") })
    val task2 = Task("Task 2", 2, { println("Task 2 executed") })
    val task3 = Task("Task 3", 3, { println("Task 3 executed") })

    // Add tasks to the priority queue
    scheduler.addTask(task1)
    scheduler.addTask(task2)
    scheduler.addTask(task3)

    // Execute tasks in the priority queue
