}

// booksHandler handles CRUD operations for all books
func booksHandler(w http.ResponseWriter, r *http.Request) {
    switch r.Method {
    case http.MethodGet:
        books, err := getBooks()
        if err != nil {
            http.Error(w, err.Error(), http.StatusInternalServerError)
            return
        }
        json.NewEncoder(w).Encode(books)
    case http.MethodPost:
        book := Book{}
        err := json.NewDecoder(r.Body).Decode(&book)
        if err != nil {
            http.Error(w, err.Error(), http.StatusBadRequest)
            return
        }
        err = createBook(&book)
        if err != nil {
            http.Error(w, err.Error(), http.StatusInternalServerError)
            return
        }
        json.NewEncoder(w).Encode(book)
    default:
        http.Error(w, "Invalid HTTP method", http.StatusMethodNotAllowed)
    }
}

// booksByIDHandler handles CRUD operations for a single book
func booksByIDHandler(w http.ResponseWriter, r *http.Request) {
    switch r.Method {
    case http.MethodGet:
        book, err := getBookByID(r.URL.Path[1:])
        if err != nil {
            http.Error(w, err.Error(), http.StatusNotFound)
            return
        }
        json.NewEncoder(w).Encode(book)
    case http.MethodPut:
        book := Book{}
        err := json.NewDecoder(r.Body).Decode(&book)
        if err != nil {
            http.Error(w, err.Error(), http.StatusBadRequest)
            return
        }
        err = updateBook(&book, r.URL.Path[1:])
        if err != nil {
            http.Error(w, err.Error(), http.StatusInternalServerError)
            return
        }
        json.NewEncoder(w).Encode(book)
    case http.MethodDelete:
        err := deleteBook(r.URL.Path[1:])
        if err != nil {
            http.Error(w, err.Error(), http.StatusInternalServerError)
            return
        }
        w.WriteHeader(http.StatusNoContent)
    default:
        http.Error(w, "Invalid HTTP method", http.StatusMethodNotAllowed)
    }
}

// getBooks retrieves all books from the database
func getBooks() ([]Book, error) {
    rows, err := db.Query("SELECT * FROM books")
    if err != nil {
        return nil, err
    }
    defer rows.Close()

    books := make([]Book, 0)
    for rows.Next() {
        var book Book
        err := rows.Scan(&book.ID, &book.Title, &book.Author)
        if err != nil {
            return nil, err
        }
        books = append(books, book)
    }

    return books, nil
}

// createBook inserts a new book into the database
func createBook(book *Book) error {
    _, err := db.Exec("INSERT INTO books (title, author) VALUES (?, ?)", book.Title, book.Author)
    return err
}

// getBookByID retrieves a book by ID from the database
func getBookByID(id int) (Book, error) {
    row := db.QueryRow("SELECT * FROM books WHERE id = ?", id)
    var book Book
    err := row.Scan(&book.ID, &book.Title, &book.Author)
    if err != nil {
        return Book{}, err
    }
    return book, nil
}

// updateBook updates an existing book in the database
func updateBook(book *Book, id int) error {
    _, err := db.Exec("UPDATE books SET title = ?, author = ? WHERE id = ?", book.Title, book.Author, id)
    return err
}

// deleteBook deletes a book by ID from the database
func deleteBook(id int) error {
    _, err := db.Exec("DELETE FROM books WHERE id = ?", id)
    return err
}
