def filter_and_summarize(csv_file):
    completed_transactions = []
    total_amount = 0
    customer_transactions = {}

    with open(csv_file, 'r') as file:
        reader = csv.DictReader(file)
        for row in reader:
            if row['Status'] != 'complete':
                continue
            amount = float(row['Amount'])
            total_amount += amount
            if row['CustomerID'] not in customer_transactions:
                customer_transactions[row['CustomerID']] = 0
            customer_transactions[row['CustomerID']] += amount
            completed_transactions.append({
                'CustomerID': row['CustomerID'],
                'Amount': amount,
                'Status': row['Status']
            })

    # Filter out completed transactions
    completed_transactions = [transaction for transaction in completed_transactions if transaction['Status'] == 'complete']

    # Calculate total amount solely for completed transactions
    total_amount = sum(transaction['Amount'] for transaction in completed_transactions)

    # List total completed transactions per customer in a JSON format
    customer_summary = {
        'completed_transactions': [
            {
                'CustomerID': customer,
                'TotalAmount': amount
            } for customer, amount in customer_transactions.items()
        ],
        'total_amount': total_amount
    }

    return json.dumps(customer_summary)

csv_file = 'customer_transactions.csv'
print(filter_and_summarize(csv_file))
