fn convert_to_fahrenheit(celsius_temps: Vec<f64>) -> Vec<f64> {
    let mut fahrenheit_temps = Vec::new();

    for temp in &celsius_temps {
        match temp {
            // If temperature is below 0°C, convert it to Fahrenheit
            temp if *temp < 0.0 => {
                fahrenheit_temps.push((temp * 9.0 / 5.0) + 32.0);
                println!("{}°C is freezing!", *temp);
            }
            // If temperature is between 0°C and 15°C, convert it to Fahrenheit
            temp if *temp >= 0.0 && *temp <= 15.0 => {
                fahrenheit_temps.push((temp * 9.0 / 5.0) + 32.0);
                println!("{}°C is cold!", *temp);
            }
            // If temperature is between 16°C and 30°C, convert it to Fahrenheit
            temp if *temp > 15.0 && *temp <= 30.0 => {
                fahrenheit_temps.push((temp * 9.0 / 5.0) + 32.0);
                println!("{}°C is warm!", *temp);
            }
            // If temperature is above 30°C, convert it to Fahrenheit
            temp => {
                fahrenheit_temps.push((temp * 9.0 / 5.0) + 32.0);
                println!("{}°C is hot!", *temp);
            }
        }
    }

    fahrenheit_temps
}

fn main() {
    let celsius_temps = vec![0.0, 10.0, 20.0, 31.0, -5.0];
    let fahrenheit_temps = convert_to_fahrenheit(celsius_temps);
    println!("Fahrenheit temperatures: {:?}", fahrenheit_temps);
}
