package main

import (
    "fmt"
    "sync"
)

func sumNumbers(nums []int) int {
    var result chan int
    result = make(chan int)

    var wg sync.WaitGroup

    wg.Add(len(nums))

    for i, num := range nums {
        go func(index int, number int) {
            defer wg.Done()
            result <- number
        }(i, num)
    }

    go func() {
        wg.Wait()
        sum := 0
        for num := range result {
            sum += num
        }
        close(result)
    }()

    return sum
}

func main() {
    nums := []int{1, 2, 3, 4, 5}
    fmt.Println(sumNumbers(nums))
}
